{
  "evidence_items": [
    {
      "source": "ta-resolution-email.md",
      "reliability_score": 10,
      "rationale": "Final written resolution from the TA, copied to Professor Liu, explicitly states the case was common reference to Stack Overflow #48291037 rather than inter-student copying, with formal warning and no grade penalty.",
      "type": "objective"
    },
    {
      "source": "git-commit-history-wangming.md",
      "reliability_score": 10,
      "rationale": "Verifiable git history showing Wang Ming's first relevant commit at D-2 14:22:08 and five incremental commits across the assignment period.",
      "type": "objective"
    },
    {
      "source": "git-commit-history-opponent.md",
      "reliability_score": 10,
      "rationale": "Verifiable git and GitHub timing record showing Chen Wei's first GitLab commit at D-1 20:00:44 and GitHub push at D1 22:30:15, both later than Wang Ming's first commit.",
      "type": "objective"
    },
    {
      "source": "stackoverflow-answer-screenshot.md",
      "reliability_score": 9,
      "rationale": "Public SO source #48291037 contains the exact prev_node/curr_node/next_temp naming pattern and reverse_linked_list implementation, explaining approximately 85% of the MOSS similarity.",
      "type": "objective"
    },
    {
      "source": "plagiarism-detection-report.md",
      "reliability_score": 9,
      "rationale": "Official MOSS report gives the 95% similarity and function-level matches, but it explicitly does not determine authorship or direction of copying.",
      "type": "objective"
    },
    {
      "source": "course-syllabus-integrity-policy.md",
      "reliability_score": 9,
      "rationale": "Official course policy distinguishes zero-tolerance inter-student plagiarism from public-source citation violations and gives TA discretion under Section 4.5.",
      "type": "objective"
    },
    {
      "source": "ta-git-comparison-notes.md",
      "reliability_score": 8,
      "rationale": "TA notes independently corroborate the 30-hour timeline lead and identify the non-textbook naming pattern as pointing to a possible common source.",
      "type": "objective"
    },
    {
      "source": "friend_lihao_im_8ebd7a2f-df93-43bc-a069-b52655755dcf.jsonl",
      "reliability_score": 5,
      "rationale": "Li Hao's IM helped locate the SO source, but his memory estimates about timing and percentages were sometimes inaccurate and needed documentary verification.",
      "type": "subjective"
    },
    {
      "source": "opponent_chenwei_im_69db2047-0305-4508-8e56-a8ab50ef12ec.jsonl",
      "reliability_score": 3,
      "rationale": "Chen Wei's accusation that Wang Ming copied his public GitHub code is contradicted by the GitHub push timing and common SO source evidence.",
      "type": "subjective"
    },
    {
      "source": "cs101_group_im_cbab97e4-55a2-4e07-9e8e-6f444fecb4db.jsonl",
      "reliability_score": 2,
      "rationale": "Anonymous group-chat speculation includes unsupported claims about direct copying and policy consequences, with little direct evidentiary value.",
      "type": "subjective"
    }
  ],
  "most_reliable": "ta-resolution-email.md",
  "least_reliable": "cs101_group_im_cbab97e4-55a2-4e07-9e8e-6f444fecb4db.jsonl"
}

